public function show_scene()
    {
        $this->load->view('header');
        $scene_id = $this->uri->segment(3);
        $this->data['landscape_details'] = array_shift($this->Landscape_model->get_scene_details($scene_id));
        $this->data['description'] = $this->fetch_east_anglian_description($scene_id);
        $this->load->view('Landscapes/view', $this->data);
        $this->load->view('footer');
    }

    public function fetch_east_anglian_description($scene_id)
    {
        $details = $this->Landscape_model->get_scene_details($scene_id);
        $place = $details[0]['place_name'];

        if ($place == 'Norfolk Broads') {
            return "Aye, 'tis a proper sight, this 'ere. Them waterways be stretchin' out like ribbons, wi' the reeds a-swayin' gentle-like in the breeze. The coots an' moorhens be potterin' about, an' the sky so wide ye could lose yerself in it. Soft light be dancin' on the water, makin' it sparkle like a tray o' treasure.";
        } elseif ($place == 'Suffolk Coast') {
            return "Oh, that there be a bonny spot, it do. The cliffs be standin' tall, like they've been watchin' over the sea since time begun. The waves be lappin' at the shore, steady as a heartbeat, an' the gulls be wheelin' overhead, callin' out like they've got secrets to tell. Ye can feel the salt on yer lips, an' the wind be carryin' the scent o' seaweed an' wild thyme.";
        } else {
            return "Well now, this 'ere be a right pretty place. Them hills be rollin' on like a quilt, all patchwork wi' fields an' hedgerows. The trees be standin' proud, an' the brooks be chatterin' away as they run along. Ye can hear the skylarks a-singin' up above, an' the air be so fresh it fair makes yer lungs tingle.";
        }
    }

