public function getSystemInfo()
{
    $pdo     = \DB::connection()->getPdo();

    $version = $pdo->query('select version()')->fetchColumn();

    $data = [
        'server'          => $_SERVER['SERVER_SOFTWARE'],
        'http_host'       => $_SERVER['HTTP_HOST'],
        'php_version'     => PHP_VERSION,
        'db_version'      => $version,
        'os'              => PHP_OS,
    ];

    return $data;
}
